export const POSTING_REASONS_NO_SUPPLIER = ['UNC-BHXH', 'BTK5011'] as const;

/** Map ReceiptTypeConfig.CustomerFilterType to CustomerSearchField defaultCustomerType. */
function resolveCustomerSearchFilterType(
  customerFilterType?: string | null,
): 'Customer' | 'Supplier' | 'Both' | undefined {
  if (!customerFilterType) return undefined;
  // 'Employee' → show all (no filter) — BE currently doesn't support Employee customerType filter
  if (customerFilterType === 'Employee') return undefined;
  if (customerFilterType === 'All') return 'Both';
  const known: Record<string, 'Customer' | 'Supplier'> = {
    Customer: 'Customer',
    Supplier: 'Supplier',
  };
  return known[customerFilterType];
}

export function useCashVoucherFormController(kind: CashVoucherKind) {
  const cfg = getCashVoucherConfig(kind);
  const id = useFormRouteId();
  const isNew = !id;
  const navigate = useInAppNavigate();
  const location = useLocation();
  const dispatch = useAppDispatch();

  const shell = resolveCashVoucherShellFromPath(location.pathname)
    ?? getCashVoucherShellProfile(defaultShellIdForKind(kind));

  const labels = getCashVoucherFormLabelsForShell(shell.id, shell.pageTitle, kind);

  const listPath = shell.listPath;
  const detailPath = shell.detailPath;

  const startInEditMode = !isNew && shouldStartFormInEditMode(
    location.search,
    location.state as { startInEditMode?: boolean } | null,
  );

  const form = useCashVoucherFormState(initialFormMode(isNew, { startInEditMode }));
  const {
    state: formState, dispatch: formDispatch,
    voucherDate, setVoucherDate,
    voucherNumber, setVoucherNumber,
    receiptKind, setReceiptKind,
    currencyCode, setCurrencyCode,
    exchangeRate, setExchangeRate,
    customerId, setCustomerId,
    customerCode, setCustomerCode,
    customerName, setCustomerName,
    customerType, setCustomerType,
    representativeName, setRepresentativeName,
    customerPhone, setCustomerPhone,
    reference, setReference,
    referenceCustomerName, setReferenceCustomerName,
    accountCode, setAccountCode,
    accountName, setAccountName,
    counterAccountCode, setCounterAccountCode,
    counterAccountName, setCounterAccountName,
    description, setDescription,
    processingLevel, setProcessingLevel,
    postingReasonCode, setPostingReasonCode,
    paymentChannelCode, setPaymentChannelCode,
    status, setStatus,
    lines, setLines, updateLine, addLine, insertLineAfter, removeLine,
    formMode, setFormMode,
    savedSnapshot, setSavedSnapshot,
    fieldErrors, setFieldErrors,
    generalErrors, setGeneralErrors,
  } = form;

  const hideSupplierForPostingReason =
    kind === 'payment' && POSTING_REASONS_NO_SUPPLIER.includes(postingReasonCode as (typeof POSTING_REASONS_NO_SUPPLIER)[number]);
  const showHeaderCustomer = !hideSupplierForPostingReason;
  const requireHeaderCustomer = kind === 'payment' && showHeaderCustomer;

  const toolbarMode = effectiveFormMode(isNew, formMode);

  const syncEditModeInUrl = useCallback((nextMode: FormMode) => {
    if (isNew) return;
    const nextSearch = nextMode === FormMode.Edit
      ? withFormEditModeSearch(location.search)
      : withoutFormEditModeSearch(location.search);
    const routerState = location.state as FormNavigateEditIntent | null;
    const nextState = nextMode === FormMode.View && routerState?.startInEditMode
      ? (() => {
        const stripped = { ...(location.state as Record<string, unknown>) };
        delete stripped.startInEditMode;
        return stripped;
      })()
      : location.state;
    const searchUnchanged = nextSearch === location.search;
    const stateUnchanged = nextState === location.state;
    if (searchUnchanged && stateUnchanged) return;
    navigate(
      { pathname: location.pathname, search: nextSearch },
      { replace: true, state: nextState },
    );
  }, [isNew, location.pathname, location.search, location.state, navigate]);

  const editIntentAppliedForIdRef = useRef<string | null>(null);

  useEffect(() => {
    if (isNew) {
      editIntentAppliedForIdRef.current = null;
      return;
    }
    const hasEditIntent = shouldStartFormInEditMode(
      location.search,
      location.state as FormNavigateEditIntent | null,
    );
    if (!hasEditIntent) {
      if (editIntentAppliedForIdRef.current === id) {
        editIntentAppliedForIdRef.current = null;
      }
      return;
    }
    if (editIntentAppliedForIdRef.current === id) return;
    editIntentAppliedForIdRef.current = id ?? null;
    setFormMode(FormMode.Edit);
  }, [isNew, id, location.search, location.state, setFormMode]);

  const [searchResultIds, setSearchResultIds] = useState<string[]>([]);
  const [showSearchSlideout, setShowSearchSlideout] = useState(false);
  const [showApproveModal, setShowApproveModal] = useState(false);
  const [showPrintModal, setShowPrintModal] = useState(false);
  const [showHistoryModal, setShowHistoryModal] = useState(false);
  const [approving, setApproving] = useState(false);
  const [printing, setPrinting] = useState(false);

  const [loading, setLoading] = useState(false);
  const [refreshing, setRefreshing] = useState(false);
  const loadedVoucherIdRef = useRef<string | null>(null);
  const [loadedVoucherId, setLoadedVoucherId] = useState<string | null>(null);
  /** Trang kết quả Tìm — next/prev dùng cache, không GET DB. */
  const searchCacheRef = useRef<Map<string, CashVoucherDto>>(new Map());
  /** Pattern B — inline errors only after first Lưu attempt. */
  const validationAttemptedRef = useRef(false);
  /** User cleared HTTT — không auto-chọn lại theo shell.paymentMedium. */
  const skipPaymentChannelAutoDefaultRef = useRef(false);
  const [saving, setSaving] = useState(false);
  const [showConfirmSaveModal, setShowConfirmSaveModal] = useState(false);
  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const [showLedgerModal, setShowLedgerModal] = useState(false);
  const [showAllocateModal, setShowAllocateModal] = useState(false);
  const [showLinkedInvoicesSlideout, setShowLinkedInvoicesSlideout] = useState(false);
  const [linkedInvoices, setLinkedInvoices] = useState<LinkedSalesInvoiceLineDto[]>([]);
  const [fmLegacyCode, setFmLegacyCode] = useState<string | null>(null);
  /** Company code the loaded voucher belongs to (null when creating new). */
  const [voucherCompanyCode, setVoucherCompanyCode] = useState<string | null>(null);
  /** VoucherRegistry.Name from CashVoucherDto (e.g. "Giấy báo có") — SSOT for tab/toolbar title. */
  const [voucherTitle, setVoucherTitle] = useState<string | undefined>(undefined);
  const [deleting, setDeleting] = useState(false);
  const [postingStatus, setPostingStatus] = useState<DocumentPostingStatus>('None');
  const [validationErrors, setValidationErrors] = useState<string[]>([]);
  const [bannerExpanded, setBannerExpanded] = useState(true);
  const [bannerClosed, setBannerClosed] = useState(false);
  const [selectedLineIndex, setSelectedLineIndex] = useState(0);
  const [highlightLineId, setHighlightLineId] = useState<string | null>(null);
  const [accountingPeriods, setAccountingPeriods] = useState<AccountingPeriodGate[]>([]);
  const [allowEditPostingAccounts, setAllowEditPostingAccounts] = useState(false);

  useEffect(() => {
    if (!highlightLineId) return undefined;
    const timer = window.setTimeout(() => setHighlightLineId(null), 2200);
    return () => window.clearTimeout(timer);
  }, [highlightLineId]);

  useEffect(() => {
    if (selectedLineIndex >= lines.length) {
      setSelectedLineIndex(Math.max(0, lines.length - 1));
    }
  }, [lines.length, selectedLineIndex]);

  useEffect(() => {
    let cancelled = false;
    const timer = setTimeout(() => {
      ktService.getPeriods()
        .then(periods => { if (!cancelled) setAccountingPeriods(periods); })
        .catch(() => { /* non-blocking — BE validates on save */ });
    }, 0);
    return () => { cancelled = true; clearTimeout(timer); };
  }, []);

  useEffect(() => {
    setValidationErrors([...collectBannerMessages(fieldErrors), ...generalErrors]);
  }, [fieldErrors, generalErrors]);

  const clearAllValidation = useCallback(() => {
    validationAttemptedRef.current = false;
    skipPaymentChannelAutoDefaultRef.current = false;
    formDispatch({ type: 'CLEAR_VALIDATION' });
    setValidationErrors([]);
    setBannerClosed(true);
  }, [formDispatch]);

  const applyVoucherFromDto = useCallback((
    v: CashVoucherDto,
    options?: { formMode?: FormMode },
  ) => {
    const { header, lines: lineStates, showDetailObject: dtoShowDetail, snap } = mapDtoToFormInit(v, kind);
    formDispatch({ type: 'INIT_HEADER_LINES', header, lines: lineStates });
    setStatus(v.status);
    setLinkedInvoices(v.linkedInvoices ?? []);
    setFmLegacyCode(resolveFmLegacyCodeDisplay(v.code, v.legacyCode));
    setVoucherCompanyCode(v.companyCode ?? null);
    setVoucherTitle(v.voucherTitle);
    setSavedSnapshot(serializeVoucherSnapshot(snap));
    // Restore showDetailObject from BE (stored in DB)
    setShowDetailObject(dtoShowDetail);
    const wantsEdit = options?.formMode !== undefined
      ? options.formMode === FormMode.Edit
      : shouldStartFormInEditMode(
        location.search,
        location.state as { startInEditMode?: boolean } | null,
      );
    setFormMode(wantsEdit ? FormMode.Edit : FormMode.View);
    formDispatch({ type: 'COMMIT_INITIAL' });
    clearAllValidation();
    if (v.customerId?.trim()) {
      const loadedCustomerId = v.customerId;
      ktService.getCustomer(loadedCustomerId)
        .then(c => setCustomerType(c.customerType ?? ''))
        .catch(() => setCustomerType(''));
    } else {
      setCustomerType('');
    }
  }, [kind, clearAllValidation, formDispatch, setStatus, setVoucherCompanyCode, setVoucherTitle, setSavedSnapshot, setFormMode, setCustomerType, location.search, location.state]);

  useEffect(() => {
    const raw = (location.state as Record<string, unknown>)?.[VOUCHER_SEARCH_CACHE_KEY];
    if (Array.isArray(raw) && raw.length > 0) {
      searchCacheRef.current = voucherSearchCacheToMap(raw as CashVoucherDto[]);
    }
  }, [location.state]);

  const receiptPrefillAppliedRef = useRef(false);
  useEffect(() => {
    if (!isNew || kind !== 'receipt' || receiptPrefillAppliedRef.current) return;
    const routerState = location.state as Record<string, unknown> | null;
    let prefill = routerState?.[RECEIPT_PREFILL_FROM_INVOICE_KEY] as ReceiptPrefillFromInvoice | undefined;
    if (!prefill) prefill = consumeReceiptPrefillFromInvoice() ?? undefined;
    if (!prefill) return;
    receiptPrefillAppliedRef.current = true;
    setReceiptKind('2');
    setCustomerId(prefill.customerId);
    setCustomerCode(prefill.customerCode ?? '');
    setCustomerName(prefill.customerName ?? '');
    setDescription(prefill.description ?? `Thu tiền HĐ ${prefill.invoiceCode}`);
    setLines([{
      ...emptyLine(),
      invoiceCode: prefill.invoiceCode,
      debitAmount: prefill.amount,
      description: prefill.description ?? `Thu tiền HĐ ${prefill.invoiceCode}`,
    }]);
    navigate(location.pathname, { replace: true, state: {} });
  }, [
    isNew,
    kind,
    location.pathname,
    location.state,
    navigate,
    setReceiptKind,
    setCustomerId,
    setCustomerCode,
    setCustomerName,
    setDescription,
    setLines,
  ]);

  const patchHeaderFieldError = useCallback((
    key: 'voucherDate' | 'customerId' | 'accountCode' | 'description',
    value: string,
  ) => {
    const rawMsg =
      key === 'customerId' && !requireHeaderCustomer
        ? undefined
        : validateVoucherHeaderField(key, value, labels.cashLabel, labels.partnerLabel);
    const msg = applyInlineValidationMessage(validationAttemptedRef.current, rawMsg);
    const next = { ...fieldErrors };
    if (msg) next[key] = msg;
    else delete next[key];
    setFieldErrors(next);
    if (key === 'customerId' || key === 'voucherDate' || key === 'accountCode' || key === 'description') {
      formDispatch({ type: 'SET_HEADER_ERROR', key, error: msg });
    }
  }, [labels.cashLabel, labels.partnerLabel, requireHeaderCustomer, fieldErrors, setFieldErrors, formDispatch]);

  const patchLineFieldError = useCallback((
    lineIndex: number,
    key: LineFieldKey,
    line: LineRow,
  ) => {
    const msg = applyInlineValidationMessage(
      validationAttemptedRef.current,
      validateLineField(lineIndex, key, line),
    );
    const next: VoucherFieldErrors = { ...fieldErrors, lines: { ...fieldErrors.lines } };
    const row = { ...(next.lines?.[lineIndex] ?? {}) };
    if (msg) row[key] = msg;
    else delete row[key];
    if (Object.keys(row).length === 0) {
      if (next.lines) delete next.lines[lineIndex];
      if (next.lines && Object.keys(next.lines).length === 0) delete next.lines;
    } else {
      next.lines = next.lines ?? {};
      next.lines[lineIndex] = row;
    }
    setFieldErrors(next);
  }, [fieldErrors, setFieldErrors]);

  const initFormName = isNew ? shell.createInitFormName : shell.editInitFormName;
  const {
    processingLevelOptions,
    defaultProcessingLevel,
    defaultAccount,
    currencyOptions,
    defaultCurrencyCode,
    defaultExchangeRate,
    formPermissions,
    paymentChannels,
    fieldDefaults,
    receiptTypeConfigs,
    initError,
    loading: initLoading,
    formTitle,
  } = useVoucherInitData(initFormName);

  /** Fallback first processing-level option when BE returns null DefaultProcessingLevel. */
  const resolvedDefaultProcessingLevel = useMemo(
    () => defaultProcessingLevel || (processingLevelOptions.length > 0 ? String(processingLevelOptions[0].value) : undefined),
    [defaultProcessingLevel, processingLevelOptions],
  );

  const selectedReceiptType = useMemo(
    () => receiptTypeConfigs.find(t => t.code === receiptKind),
    [receiptTypeConfigs, receiptKind],
  );

  const postingReasonVoucherTypeCode = useMemo(
    () => resolvePostingReasonVoucherTypeCode(shell),
    [shell.voucherRegistryCode],
  );

  const postingReasonIsCash = useMemo(
    () => shell.paymentMedium === 'cash' ? true : shell.paymentMedium === 'bank' ? false : undefined,
    [shell.paymentMedium],
  );

  const [postingReasonRules, setPostingReasonRules] = useState<PostingReasonInitItem[]>([]);

  useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      ktService.getPostingReasonRules({
        voucherTypeCode: postingReasonVoucherTypeCode,
        isCash: postingReasonIsCash,
      })
        .then(rows => {
          if (!cancelled) {
            setPostingReasonRules(rows.map(mapPostingReasonRuleToInitItem));
          }
        })
        .catch(() => {
          if (!cancelled) setPostingReasonRules([]);
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [postingReasonVoucherTypeCode, postingReasonIsCash]);

  const postingReasonByCode = useMemo(
    () => new Map(postingReasonRules.map(r => [r.code, r])),
    [postingReasonRules],
  );

  const paymentChannelByCode = useMemo(
    () => new Map(paymentChannels.map(ch => [ch.code, ch])),
    [paymentChannels],
  );

  const postingReasonSearchConfig = useMemo(
    () => createPostingReasonSearchConfig(postingReasonRules),
    [postingReasonRules],
  );

  const paymentChannelSearchConfig = useMemo(
    () => createPaymentChannelSearchConfig(paymentChannels),
    [paymentChannels],
  );

  const selectedPostingReason = useMemo(
    () => (postingReasonCode ? postingReasonByCode.get(postingReasonCode) : undefined),
    [postingReasonCode, postingReasonByCode],
  );

  const selectedPaymentChannel = useMemo(
    () => (paymentChannelCode ? paymentChannelByCode.get(paymentChannelCode) : undefined),
    [paymentChannelCode, paymentChannelByCode],
  );

  const isSuggestOnly = selectedPostingReason?.suggestOnly === true;

  const showAllowEditPostingCheckbox = !isSuggestOnly && selectedPostingReason?.allowEditPostingAccounts === true;

  const postingAccountsLocked = !!selectedPostingReason && !isSuggestOnly && !(
    showAllowEditPostingCheckbox && allowEditPostingAccounts
  );

  const applyPostingReasonAccounts = useCallback((
    rule: PostingReasonInitItem,
    invoiceGrid: boolean,
  ) => {
    const { cashAccountCode, counterAccountCode } = resolvePostingReasonAccounts(kind, rule);
    if (cashAccountCode) {
      setAccountCode(cashAccountCode);
      setAccountName('');
    }
    if (counterAccountCode) {
      if (invoiceGrid) {
        setCounterAccountCode(counterAccountCode);
        setCounterAccountName('');
      } else if (lines.length > 0) {
        setLines(lines.map(l => ({
          ...l,
          accountCode: counterAccountCode,
          accountName: '',
        })));
      }
    }
  }, [
    kind,
    lines,
    setAccountCode,
    setAccountName,
    setCounterAccountCode,
    setCounterAccountName,
    setLines,
  ]);

  const handlePaymentChannelSelect = useCallback((channel: PaymentChannelInitItem) => {
    setPaymentChannelCode(channel.code);
    const shouldApplyChannelCash = !selectedPostingReason || postingAccountsLocked;
    if (!shouldApplyChannelCash) return;
    const cashAccount = resolvePaymentChannelCashAccount(kind, channel);
    if (cashAccount) {
      setAccountCode(cashAccount);
      setAccountName('');
    }
  }, [
    kind,
    selectedPostingReason,
    postingAccountsLocked,
    setPaymentChannelCode,
    setAccountCode,
    setAccountName,
  ]);

  useEffect(() => {
    if (!isNew) {
      skipPaymentChannelAutoDefaultRef.current = false;
      return;
    }
    if (skipPaymentChannelAutoDefaultRef.current) return;
    if (paymentChannelCode || paymentChannels.length === 0) return;

    // Read default from init-data FieldDefaults (VoucherRegistryFieldDefaults table) — cấm hardcode UI
    const defaultChannelCode = fieldDefaults?.['paymentChannelCode'];
    if (defaultChannelCode) {
      const channel = paymentChannels.find(ch => ch.code === defaultChannelCode);
      if (channel) {
        handlePaymentChannelSelect(channel);
        return;
      }
    }

    // Fallback: infer from paymentMedium if no configured default
    if (!shell.lockPaymentMedium) return;
    if (shell.paymentMedium === 'bank') {
      const bank = paymentChannels.find(ch => ch.debitAccountCode.startsWith('112'))
        ?? paymentChannels[0];
      if (bank) handlePaymentChannelSelect(bank);
      return;
    }
    if (shell.paymentMedium === 'cash') {
      const cash = paymentChannels.find(ch => ch.debitAccountCode.startsWith('111')) ?? paymentChannels[0];
      if (cash) handlePaymentChannelSelect(cash);
    }
  }, [
    isNew,
    shell.lockPaymentMedium,
    shell.paymentMedium,
    paymentChannelCode,
    paymentChannels,
    fieldDefaults,
    handlePaymentChannelSelect,
  ]);

  const handlePaymentChannelClear = useCallback(() => {
    skipPaymentChannelAutoDefaultRef.current = true;
    setPaymentChannelCode('');
  }, [setPaymentChannelCode]);

  const processingOpts = useMemo(() => {
    const opts = resolveProcessingLevelSelectOptions(processingLevelOptions, resolvedDefaultProcessingLevel);
    // Ensure current value always has a matching option — Select will show blank otherwise
    if (processingLevel && !opts.some(o => String(o.value) === processingLevel)) {
      return [...opts, { value: processingLevel, label: `Mức ${processingLevel}` }];
    }
    return opts;
  }, [processingLevelOptions, resolvedDefaultProcessingLevel, processingLevel]);
  const receiptKindOpts = receiptTypeConfigs.map(c => ({ value: c.code, label: c.label }));

  // Default receiptKind từ BE configs — fallback 'all' hoặc config đầu tiên
  useEffect(() => {
    if (!isNew) return;
    if (receiptTypeConfigs.length > 0 && !receiptKind) {
      const first = receiptTypeConfigs[0];
      setReceiptKind(first.code);
    }
  }, [isNew, receiptTypeConfigs, receiptKind, setReceiptKind]);

  const [showReceiptKindConfirm, setShowReceiptKindConfirm] = useState(false);
  const [receiptKindPendingChange, setReceiptKindPendingChange] = useState<string | null>(null);
  const [showCustomerConfirm, setShowCustomerConfirm] = useState(false);
  const [customerPendingData, setCustomerPendingData] = useState<{
    id: string;
    code: string;
    name: string;
    customerType?: string;
  } | null>(null);

  const handleReceiptKindConfirmChange = () => {
    const newKind = receiptKindPendingChange;
    if (newKind === null) {
      setShowReceiptKindConfirm(false);
      setReceiptKindPendingChange(null);
      return;
    }

    const oldKind = receiptKind;

    // ── Detect which header fields must be cleared ──
    let clearHeaderCustomer = false;
    if ((oldKind === '1' || oldKind === '2') && newKind === '3') {
      // Types 1/2 → type 3 (Nhiều ĐT): KH chuyển xuống dòng
      clearHeaderCustomer = true;
    }
    if (customerId.trim() && customerType.trim()) {
      const newConfig = receiptTypeConfigs.find(t => t.code === newKind);
      const newCustomerFilter = newConfig?.customerFilterType;
      if (newCustomerFilter && newCustomerFilter !== 'All' && newCustomerFilter !== customerType) {
        clearHeaderCustomer = true;
      }
    }

    // ── Apply header clears ──
    if (oldKind === '1' && newKind !== '1') {
      // Type 1 (Theo HĐ) → non-1: TK đối ứng header không còn ý nghĩa
      setCounterAccountCode('');
      setCounterAccountName('');
    }
    if (clearHeaderCustomer) {
      setCustomerId('');
      setCustomerCode('');
      setCustomerName('');
      setCustomerType('');
      setCustomerPhone('');
    }

    // ── Clear line fields incompatible with new type ──
    let lineDataChanged = false;
    const updatedLines = lines.map(line => {
      let updated = { ...line };

      if (oldKind === '1' && newKind !== '1') {
        // Leaving type 1: xoá thông tin hóa đơn trên dòng
        updated.invoiceCode = '';
        updated.invoiceDate = '';
        updated.invoiceTotalAmount = 0;
        updated.invoicePaidAmount = 0;
        updated.invoiceRemainingAmount = 0;
        if (line.invoiceCode) lineDataChanged = true;
      }

      if (oldKind === '3' && newKind !== '3') {
        // Leaving type 3: xoá KH trên từng dòng
        updated.customerId = '';
        updated.customerCode = '';
        updated.customerName = '';
        if (line.customerId) lineDataChanged = true;
      }

      // Also clear line KH/invoice if header customer was cleared due to type conflict
      if (clearHeaderCustomer && (line.customerId.trim() || line.invoiceCode.trim())) {
        updated.customerId = '';
        updated.customerCode = '';
        updated.customerName = '';
        updated.invoiceCode = '';
        updated.invoiceDate = '';
        updated.invoiceTotalAmount = 0;
        updated.invoicePaidAmount = 0;
        updated.invoiceRemainingAmount = 0;
        lineDataChanged = true;
      }

      return updated;
    });

    // Apply new receipt kind
    setReceiptKind(newKind);

    // Update lines if any field was cleared
    if (lineDataChanged) {
      setLines(updatedLines);
    }

    setShowReceiptKindConfirm(false);
    setReceiptKindPendingChange(null);
  };
  const handleReceiptKindCancelChange = () => {
    setShowReceiptKindConfirm(false);
    setReceiptKindPendingChange(null);
  };

  /** Kiểm tra nếu lines có dữ liệu KH để quyết định có cần confirm không. */
  const customerDataExistsOnLines = lines.some(l =>
    l.customerId.trim() !== '' || l.invoiceCode.trim() !== '',
  );

  const handleRequestCustomerChange = (customerData: { id: string; code: string; name: string; customerType?: string }) => {
    // Chỉ show confirm nếu có dữ liệu KH/invoice trên lines — nếu chưa có gì, set ngay
    if (!customerDataExistsOnLines) {
      setCustomerId(customerData.id);
      setCustomerCode(customerData.code);
      setCustomerName(customerData.name);
      if (customerData.customerType) {
        setCustomerType(customerData.customerType);
      }
      return;
    }
    setCustomerPendingData(customerData);
    setShowCustomerConfirm(true);
  };
  const handleCustomerConfirmChange = () => {
    if (customerPendingData) {
      setCustomerId(customerPendingData.id);
      setCustomerCode(customerPendingData.code);
      setCustomerName(customerPendingData.name);
      if (customerPendingData.customerType) {
        setCustomerType(customerPendingData.customerType);
      }

      // Clear dữ liệu KH/invoice trên lines vì KH đã đổi
      const hasLineCustomerData = lines.some(l =>
        l.customerId.trim() !== '' || l.invoiceCode.trim() !== '',
      );
      if (hasLineCustomerData) {
        setLines(lines.map(l => ({
          ...l,
          customerId: '',
          customerCode: '',
          customerName: '',
          invoiceCode: '',
          invoiceDate: '',
          invoiceTotalAmount: 0,
          invoicePaidAmount: 0,
          invoiceRemainingAmount: 0,
        })));
      }
    }
    setShowCustomerConfirm(false);
    setCustomerPendingData(null);
  };
  const handleCustomerCancelChange = () => {
    setShowCustomerConfirm(false);
    setCustomerPendingData(null);
  };

  /** Kiểm tra có dữ liệu không tương thích giữa form hiện tại và loại phiếu mới.
   *  Chỉ show confirm khi thực sự có conflict — VD: đã có KH loại Customer mà đổi qua
   *  loại phiếu yêu cầu Supplier, hoặc đã có HĐ trên dòng mà đổi qua loại không cần HĐ. */
  const getReceiptKindConflictData = useCallback((newKind: string) => {
    const oldKind = receiptKind;
    if (oldKind === newKind) return { hasConflict: false };

    // 1. old=1 → new≠1: invoice data on lines or counterAccount header
    if (oldKind === '1' && newKind !== '1') {
      if (lines.some(l => l.invoiceCode.trim() !== '') || counterAccountCode.trim()) {
        return { hasConflict: true };
      }
    }

    // 2. old=3 → new≠3: customer data on lines
    if (oldKind === '3' && newKind !== '3') {
      if (lines.some(l => l.customerId.trim() !== '')) {
        return { hasConflict: true };
      }
    }

    // 3. old=1/2 → new=3: header customer chuyển xuống dòng
    if ((oldKind === '1' || oldKind === '2') && newKind === '3') {
      if (customerId.trim()) {
        return { hasConflict: true };
      }
    }

    // 4. Header customer type conflict với customerFilterType của loại mới
    if (customerId.trim() && customerType.trim()) {
      const newConfig = receiptTypeConfigs.find(t => t.code === newKind);
      const newCustomerFilter = newConfig?.customerFilterType;
      if (newCustomerFilter && newCustomerFilter !== 'All' && newCustomerFilter !== customerType) {
        return { hasConflict: true };
      }
    }

    return { hasConflict: false };
  }, [receiptKind, receiptTypeConfigs, customerId, customerType, lines, counterAccountCode]);

  const receiptKindLocked = lines.some(l =>
    l.accountCode.trim() !== ''
    || Number(l.debitAmount) > 0
    || l.description.trim() !== ''
    || l.invoiceCode.trim() !== ''
    || l.customerId.trim() !== '',
  );

  /** Hiển thị đối tượng chi tiết (checkbox on lines grid) — default from config or false. */
  const [showDetailObject, setShowDetailObject] = useState(
    !!selectedReceiptType?.showDetailObject,
  );

  // Sync showDetailObject when receiptKind changes
  useEffect(() => {
    if (selectedReceiptType) {
      setShowDetailObject(selectedReceiptType.showDetailObject);
    }
  }, [kind, receiptKind, selectedReceiptType]);

  const showLineCustomer = showDetailObject;
  const showInvoiceGrid = selectedReceiptType?.showInvoiceGrid ?? receiptKind === '1';
  const showCounterAccountHeader = showInvoiceGrid;
  const showAllocateBtn = kind === 'receipt'
    && !showInvoiceGrid
    && !showDetailObject
    && !!customerId
    && (selectedReceiptType?.customerFilterType === 'Customer'
      || selectedReceiptType?.customerFilterType === 'Supplier'
      || (!selectedReceiptType && receiptKind === '2'));
  const canViewLinkedInvoices = kind === 'receipt' && !isNew && linkedInvoices.length > 0;

  /** Map config customerFilterType to CustomerSearchField defaultCustomerType. */
  const headerCustomerFilterType = resolveCustomerSearchFilterType(selectedReceiptType?.customerFilterType);
  const lineCustomerFilterType = resolveCustomerSearchFilterType(selectedReceiptType?.customerFilterType);

  const customerSearchConfigOptions = useMemo(() => {
    if (!headerCustomerFilterType) return undefined;
    return { customerType: headerCustomerFilterType };
  }, [headerCustomerFilterType]);

  const handlePostingReasonSelect = useCallback((rule: PostingReasonInitItem) => {
    setPostingReasonCode(rule.code);
    setAllowEditPostingAccounts(false);
    applyPostingReasonAccounts(rule, false); // Always per-line TK
    // Auto-fill diễn giải = tên định khoản khi description đang trống (GAP-P2-DESCRIPTION-AUTO)
    if (!description?.trim()) {
      setDescription(rule.name);
    }
  }, [
    description,
    setPostingReasonCode,
    setDescription,
    applyPostingReasonAccounts,
  ]);

  const handlePostingReasonClear = useCallback(() => {
    setPostingReasonCode('');
    setAllowEditPostingAccounts(false);
  }, [setPostingReasonCode]);

  const handleAllowEditPostingAccountsChange = useCallback((checked: boolean) => {
    setAllowEditPostingAccounts(checked);
    if (!checked && selectedPostingReason) {
      applyPostingReasonAccounts(selectedPostingReason, false);
    }
  }, [
    selectedPostingReason,
    applyPostingReasonAccounts,
  ]);

  const [headerExpanded, setHeaderExpanded] = useState(true);
  const expandHeaderAfterSaveRef = useRef(false);

  useEffect(() => {
    if (!isNew || !resolvedDefaultProcessingLevel || processingLevel === resolvedDefaultProcessingLevel) return;
    setProcessingLevel(resolvedDefaultProcessingLevel);
  }, [isNew, resolvedDefaultProcessingLevel, processingLevel, setProcessingLevel]);

  useApplyVoucherAccountDefaultOnce(
    isNew,
    accountCode,
    defaultAccount,
    setAccountCode,
    setAccountName,
  );

  useEffect(() => {
    if (!isNew) return;
    const { currencyCode: code, exchangeRate: rate } = resolveVoucherCurrencyDefaults(
      defaultCurrencyCode,
      defaultExchangeRate,
    );
    const rateStr = String(rate);
    if (currencyCode !== code) setCurrencyCode(code);
    if (exchangeRate !== rateStr) setExchangeRate(rateStr);
  }, [
    isNew,
    defaultCurrencyCode,
    defaultExchangeRate,
    currencyCode,
    exchangeRate,
    setCurrencyCode,
    setExchangeRate,
  ]);

  const tid = (suffix: string) => `kt-${shell.id}-${suffix}`;
  const validationBannerId = tid('validation-banner');

  const totalAmount = lines.reduce((s, l) => s + (Number(l.debitAmount) || 0), 0);
  const saveLabel = labels.saveButton;

  const buildSnapshot = useCallback(
    (): VoucherFormSnapshot => buildSnapshotFromState(formState, { showInvoiceGrid, defaultProcessingLevel: resolvedDefaultProcessingLevel }),
    [formState, showInvoiceGrid, resolvedDefaultProcessingLevel],
  );

  const currentSnapshot = useMemo(
    () => serializeVoucherSnapshot(buildSnapshot()),
    [buildSnapshot],
  );

  const isDirty = savedSnapshot !== null && !snapshotsEqual(savedSnapshot, currentSnapshot);

  /** Sync baseline after Lưu thành công — clears unsaved modal on navigate/back */
  const markSnapshotSaved = useCallback(() => {
    setSavedSnapshot(serializeVoucherSnapshot(buildSnapshot()));
  }, [buildSnapshot]);

  const {
    showUnsavedModal,
    guardedAction,
    confirmLeave,
    cancelLeave,
  } = useUnsavedChangesGuard(isDirty, isEditingMode(toolbarMode));

  const resetEmptyForm = useCallback(() => {
    formDispatch({ type: 'RESET_EMPTY' });
    setStatus('Draft');
    clearAllValidation();
    setSavedSnapshot(null);
  }, [clearAllValidation, formDispatch, setStatus, setSavedSnapshot]);

  const applySnapshot = useCallback((snap: VoucherFormSnapshot, resetSaved: boolean) => {
    setVoucherDate(toDateOnlyInputValue(snap.voucherDate));
    setVoucherNumber('');
    setReceiptKind(snap.receiptKind || '2');
    setCustomerId(snap.customerId);
    setCustomerCode(snap.customerCode);
    setCustomerName(snap.customerName);
    setRepresentativeName(snap.representativeName);
    setCustomerPhone(snap.customerPhone);
    setReference(snap.reference);
    setReferenceCustomerName(snap.referenceCustomerName);
    setAccountCode(snap.accountCode);
    setAccountName(snap.accountName);
    setCounterAccountCode(snap.counterAccountCode ?? '');
    setCounterAccountName(snap.counterAccountName ?? '');
    setDescription(snap.description);
    setProcessingLevel(snap.processingLevel);
    setLines(
      snap.lines.length > 0
        ? snap.lines.map(l => ({
          accountCode: l.accountCode,
          accountName: l.accountName ?? '',
          debitAmount: l.debitAmount,
          description: l.description,
          costCenterCode: l.costCenterCode ?? '',
          customerId: l.customerId ?? '',
          customerCode: l.customerCode ?? '',
          customerName: l.customerName ?? '',
          invoiceId: l.invoiceId ?? '',
          invoiceCode: l.invoiceCode ?? '',
          invoiceDate: l.invoiceDate ?? '',
          invoiceTotalAmount: l.invoiceTotalAmount ?? 0,
          invoicePaidAmount: l.invoicePaidAmount ?? 0,
          invoiceRemainingAmount: l.invoiceRemainingAmount ?? 0,
        }))
        : [emptyLine()],
    );
    if (resetSaved) {
      setStatus('Draft');
      setSavedSnapshot(serializeVoucherSnapshot({
        ...snap,
        voucherDate: toDateOnlyInputValue(snap.voucherDate),
      }));
    }
  }, []);

  const closeOverlays = useCallback(() => {
    setShowSearchSlideout(false);
    setShowApproveModal(false);
    setShowPrintModal(false);
    setShowDeleteModal(false);
    setShowAllocateModal(false);
    setShowLedgerModal(false);
  }, []);

  const applyCopySnapshot = useCallback(
    (snap: VoucherFormSnapshot) => applySnapshot(snap, true),
    [applySnapshot],
  );

  const { copySourceVoucherCode } = useVoucherFormRoute<VoucherFormSnapshot>({
    isNew,
    id,
    location,
    navigate,
    setFormMode,
    setSearchResultIds,
    resetEmptyForm,
    applyCopySnapshot,
    initNewSavedSnapshot: markSnapshotSaved,
    onRouteChange: closeOverlays,
  });

  useEffect(() => {
    if (isNew) {
      loadedVoucherIdRef.current = null;
      setLoadedVoucherId(null);
      return;
    }
    let cancelled = false;
    const createHydrate = (location.state as Record<string, unknown> | null)?.[CASH_VOUCHER_CREATE_HYDRATE_KEY] as CashVoucherDto | undefined;
    if (createHydrate?.id === id) {
      searchCacheRef.current.set(id!, createHydrate);
      applyVoucherFromDto(createHydrate, { formMode: FormMode.View });
      loadedVoucherIdRef.current = id!;
      setLoadedVoucherId(id!);
      setLoading(false);
      setRefreshing(false);
      const nextState = { ...(location.state as Record<string, unknown> ?? {}) };
      delete nextState[CASH_VOUCHER_CREATE_HYDRATE_KEY];
      navigate(
        { pathname: location.pathname, search: location.search },
        { replace: true, state: nextState },
      );
      return () => { cancelled = true; };
    }

    if (loadedVoucherIdRef.current === id) {
      return () => { cancelled = true; };
    }

    const cached = searchCacheRef.current.get(id!);
    const isInitialLoad = loadedVoucherIdRef.current === null;

    if (cached) {
      applyVoucherFromDto(cached);
      loadedVoucherIdRef.current = id!;
      setLoadedVoucherId(id!);
      setLoading(false);
      setRefreshing(false);
      return () => { cancelled = true; };
    }

    if (isInitialLoad) setLoading(true);
    else setRefreshing(true);

    const t = setTimeout(() => {
      void (async () => {
        try {
          const v = await cfg.get(id!);
          if (cancelled) return;
          searchCacheRef.current.set(id!, v);
          if (searchCacheRef.current.size > VOUCHER_SEARCH_CACHE_MAX) {
            const keep = new Set(searchResultIds);
            for (const key of [...searchCacheRef.current.keys()]) {
              if (!keep.has(key)) searchCacheRef.current.delete(key);
            }
          }
          applyVoucherFromDto(v);
          loadedVoucherIdRef.current = id!;
          setLoadedVoucherId(id!);
        } catch (err) {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, 'Không thể tải chứng từ. Vui lòng thử lại.'),
              type: 'error',
            });
          }
        } finally {
          if (!cancelled) {
            setLoading(false);
            setRefreshing(false);
          }
        }
      })();
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [id, kind, cfg, dispatch, applyVoucherFromDto, searchResultIds, location.pathname, location.search, location.state, navigate]);

  const applyPostedCashVoucher = useCallback(async (voucherId: string) => {
    const v = await cfg.get(voucherId);
    applyVoucherFromDto(v, { formMode: FormMode.View });
    setPostingStatus('Posted');
  }, [cfg, applyVoucherFromDto]);

  const reloadCashVoucherFromServer = useCallback(async (voucherId: string) => {
    const v = await cfg.get(voucherId);
    applyVoucherFromDto(v, { formMode: FormMode.View });
  }, [cfg, applyVoucherFromDto]);

  const refreshPostingStatusAfterLevelChange = useCallback(async (
    previousLevel: string,
    newLevel: string,
    voucherId?: string,
  ) => {
    if (!voucherId) return;
    try {
      await syncPostingAfterLevelChange({
        previousLevel,
        newLevel,
        voucherId,
        getPostingStatus: cfg.getPostingStatus,
        onPostingStatus: setPostingStatus,
        reloadDocument: reloadCashVoucherFromServer,
        onPostSuccess: () => {
          dispatchAppToast(dispatch, { message: 'Ghi sổ thành công', type: 'success' });
        },
        onError: message => {
          dispatchAppToast(dispatch, { message, type: 'error' });
        },
      });
    } catch {
      /* optional — không chặn form */
    }
  }, [cfg, dispatch, reloadCashVoucherFromServer]);

  useEffect(() => {
    if (isNew || !id) {
      setPostingStatus('None');
      return undefined;
    }
    let cancelled = false;
    const t = setTimeout(() => {
      void (async () => {
        try {
          await loadPostingStatusForOpenForm({
            voucherId: id,
            getPostingStatus: cfg.getPostingStatus,
            onPostingStatus: status => {
              if (!cancelled) setPostingStatus(status);
            },
            reloadIfPosted: async () => {
              // Data already loaded by the main GET effect — skip redundant fetch
              return true;
            },
            onError: message => {
              if (!cancelled) {
                dispatchAppToast(dispatch, { message, type: 'error' });
              }
            },
          });
        } catch {
          /* optional — không chặn form */
        }
      })();
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [id, isNew, cfg, dispatch]);

  /** Poll khi job ghi sổ đang chạy — cập nhật toolbar sau phê duyệt mức 9. */
  useEffect(() => {
    if (isNew || !id) return undefined;
    if (postingStatus !== 'Queued' && postingStatus !== 'Processing') return undefined;

    let cancelled = false;
    const timer = window.setInterval(() => {
      void (async () => {
        try {
          const ps = await cfg.getPostingStatus(id);
          if (cancelled) return;
          setPostingStatus(ps.postingStatus);
          if (ps.postingStatus === 'Posted') {
            await applyPostedCashVoucher(id);
            dispatchAppToast(dispatch, { message: 'Ghi sổ thành công', type: 'success' });
          } else if (ps.postingStatus === 'Failed') {
            if (ps.lastError) {
              dispatchAppToast(dispatch, { message: ps.lastError, type: 'error' });
            }
          }
        } catch {
          /* optional */
        }
      })();
    }, 2000);

    return () => {
      cancelled = true;
      window.clearInterval(timer);
    };
  }, [isNew, id, postingStatus, cfg, dispatch, applyPostedCashVoucher]);

  const buildLines = (cash: string) =>
    lines.map(l => {
      const counter = l.accountCode || counterAccountCode;
      return {
        debitAccountCode: kind === 'receipt' ? cash : counter,
        creditAccountCode: kind === 'receipt' ? counter : cash,
        amount: Number(l.debitAmount),
        description: l.description || undefined,
        customerId: l.customerId || undefined,
        costCenterCode: l.costCenterCode || undefined,
        invoiceCode: l.invoiceCode || undefined,
      };
    });

  const resolveInvoiceForLine = useCallback(async (idx: number, code: string) => {
    if (!customerId || !code.trim()) return;
    try {
      const items = await ktService.getUnpaidInvoices(customerId);
      const inv = items.find(i => i.code.toLowerCase() === code.trim().toLowerCase());
      if (!inv) {
        dispatchAppToast(dispatch, { message: `Không tìm thấy HĐ ${code} chưa thanh toán của khách hàng.`, type: 'warning' });
        return;
      }
      setLines(lines.map((l, i) => (i === idx ? {
        ...l,
        invoiceId: inv.id,
        invoiceCode: inv.code,
        invoiceDate: toDateOnlyInputValue(inv.invoiceDate),
        invoiceTotalAmount: inv.totalAmount,
        invoicePaidAmount: inv.paidAmount,
        invoiceRemainingAmount: inv.remainingAmount,
        debitAmount: inv.remainingAmount,
        description: `Thu tiền HĐ ${inv.code}`,
      } : l)));
    } catch (e: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(e, 'Không tra cứu được hóa đơn.'),
        type: 'error',
      });
    }
  }, [customerId, dispatch]);

  const handleAllocateConfirm = useCallback((allocated: AllocatedInvoiceLine[]) => {
    const templateAccount = lines.find(l => l.accountCode.trim())?.accountCode ?? '';
    const templateAccountName = lines.find(l => l.accountName.trim())?.accountName ?? '';
    setLines(allocated.map(a => ({
      ...emptyLine(),
      accountCode: templateAccount,
      accountName: templateAccountName,
      debitAmount: a.amount,
      description: a.description,
      invoiceId: a.invoiceId,
      invoiceCode: a.invoiceCode,
      invoiceDate: a.invoiceDate,
      invoiceTotalAmount: a.invoiceTotalAmount,
      invoicePaidAmount: a.invoicePaidAmount,
      invoiceRemainingAmount: a.invoiceRemainingAmount,
    })));
  }, [lines]);

  const buildPayload = () => mapFormStateToPayload(formState, cfg, kind, {
    showInvoiceGrid,
    showDetailObject,
    totalAmount,
    voucherShell: shell.voucherShell,
    defaultProcessingLevel: resolvedDefaultProcessingLevel,
  });

  const cashVoucherValidate = useCashVoucherValidate({
    state: formState,
    dispatch: formDispatch,
    cashLabel: labels.cashLabel,
    partnerLabel: labels.partnerLabel,
    requireCustomerId: requireHeaderCustomer,
    tid,
    validationBannerId,
    processingLevel,
    defaultProcessingLevel: resolvedDefaultProcessingLevel,
    accountingPeriods,
    onProcessingLevelMissing: () => {
      dispatchAppToast(dispatch, { message: 'Mức xử lý là bắt buộc', type: 'error' });
    },
  });

  const cashVoucherSubmit = useCashVoucherSubmit({
    kind,
    cfg,
    state: formState,
    dispatch: formDispatch,
    isNew,
    id,
    showInvoiceGrid,
    showDetailObject,
    totalAmount,
    voucherShell: shell.voucherShell,
    detailPath,
    saveSuccessLabel: `Tạo ${labels.title.toLowerCase()} thành công`,
    navigate,
    appDispatch: dispatch,
    defaultProcessingLevel: resolvedDefaultProcessingLevel,
    onSaveSuccessNew: (createdId, code) => {
      setVoucherNumber(code);
      setFormMode(FormMode.View);
      syncEditModeInUrl(FormMode.View);
      expandHeaderAfterSaveRef.current = true;
      setHeaderExpanded(true);
      markSnapshotSaved();
      void refreshPostingStatusAfterLevelChange('', processingLevel, createdId);
    },
    onSaveSuccessUpdate: (updated) => {
      const levelBeforeSave = processingLevel;
      if (id) searchCacheRef.current.set(id, updated);
      applyVoucherFromDto(updated, { formMode: FormMode.View });
      syncEditModeInUrl(FormMode.View);
      expandHeaderAfterSaveRef.current = true;
      setHeaderExpanded(true);
      const newLevel = updated.processingLevel ?? levelBeforeSave;
      void refreshPostingStatusAfterLevelChange(levelBeforeSave, newLevel, id);
    },
  });

  const handleSave = async () => {
    validationAttemptedRef.current = true;
    if (!cashVoucherValidate.run()) {
      setBannerClosed(false);
      setBannerExpanded(true);
      return;
    }
    // Show confirm modal before proceeding — skip for Copy (Luu khong qua modal)
    const isCopy = isNew && Boolean(copySourceVoucherCode?.trim());
    if (!isCopy) {
      setShowConfirmSaveModal(true);
      return;
    }
    setSaving(true);
    try {
      const saved = await cashVoucherSubmit.saveWithErrorToast();
      if (saved) {
        expandHeaderAfterSaveRef.current = true;
        setHeaderExpanded(true);
      }
    } finally {
      setSaving(false);
    }
  };

  const handleConfirmSave = async () => {
    setShowConfirmSaveModal(false);
    setSaving(true);
    try {
      const saved = await cashVoucherSubmit.saveWithErrorToast();
      if (saved) {
        expandHeaderAfterSaveRef.current = true;
        setHeaderExpanded(true);
      }
    } finally {
      setSaving(false);
    }
  };

  /** Sau Lưu + navigate Create→View — đảm bảo header full (tránh batch/race với route) */
  useEffect(() => {
    if (!saving && expandHeaderAfterSaveRef.current) {
      setHeaderExpanded(true);
      expandHeaderAfterSaveRef.current = false;
    }
  }, [saving, id, formMode]);

  const handleDelete = async () => {
    if (isNew) return;
    setDeleting(true);
    try {
      await cfg.remove(id!);
      dispatchAppToast(dispatch, { message: 'Xóa thành công', type: 'success' });
      navigate(listPath);
    } catch (e: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(e, 'Xóa thất bại. Vui lòng thử lại.'),
        type: 'error',
      });
    } finally {
      setDeleting(false);
      setShowDeleteModal(false);
    }
  };

  const handleAddLine = () => {
    if (lines.length === 0) return;
    const afterIdx = selectedLineIndex >= 0 && selectedLineIndex < lines.length
      ? selectedLineIndex
      : lines.length - 1;
    const insertAt = afterIdx + 1;

    // Khi đã khóa định khoản — tự động fill tài khoản đối ứng từ lý do định khoản cho dòng mới
    let prefill = emptyCashVoucherLine();
    if (postingAccountsLocked && selectedPostingReason) {
      const { counterAccountCode } = resolvePostingReasonAccounts(kind, selectedPostingReason);
      if (counterAccountCode) {
        prefill = { ...prefill, accountCode: counterAccountCode };
      }
    }

    const lineId = insertLineAfter(afterIdx, prefill);
    const shifted = insertLineFieldErrors(fieldErrors.lines, insertAt);
    setFieldErrors({ ...fieldErrors, lines: shifted });
    setSelectedLineIndex(insertAt);
    setHighlightLineId(lineId);
    setGeneralErrors(generalErrors.filter(m => m !== 'Phải có ít nhất 1 dòng định khoản'));
  };

  const handleCopyLine = () => {
    if (lines.length === 0) return;
    const afterIdx = selectedLineIndex >= 0 && selectedLineIndex < lines.length
      ? selectedLineIndex
      : lines.length - 1;
    const source = lines[afterIdx];
    if (!source) return;
    const insertAt = afterIdx + 1;
    const lineId = insertLineAfter(afterIdx, { ...source });
    const shifted = insertLineFieldErrors(fieldErrors.lines, insertAt);
    setFieldErrors({ ...fieldErrors, lines: shifted });
    setSelectedLineIndex(insertAt);
    setHighlightLineId(lineId);
    setGeneralErrors(generalErrors.filter(m => m !== 'Phải có ít nhất 1 dòng định khoản'));
  };

  const handleSelectLine = (idx: number) => setSelectedLineIndex(idx);

  const handleRemoveLine = (idx: number) => {
    if (lines.length <= 1) {
      dispatchAppToast(dispatch, { message: 'Phải có ít nhất 1 dòng định khoản', type: 'warning' });
      return;
    }
    const removedId = formState.lines[idx]?.lineId;
    removeLine(idx);
    const shifted = shiftTamUngLineFieldErrors(fieldErrors.lines, idx);
    setFieldErrors({ ...fieldErrors, lines: shifted });
    setSelectedLineIndex(prev => {
      if (prev > idx) return prev - 1;
      if (prev === idx) return Math.max(0, idx - 1);
      return prev;
    });
    if (removedId && highlightLineId === removedId) {
      setHighlightLineId(null);
    }
  };
  const handleUpdateLine = (idx: number, patch: Partial<LineRow>) => {
    updateLine(idx, patch);
    const updated = { ...lines[idx], ...patch };
    if (updated) {
      if ('accountCode' in patch || 'accountName' in patch) {
        patchLineFieldError(idx, 'accountCode', updated);
      }
      if ('debitAmount' in patch) {
        patchLineFieldError(idx, 'debitAmount', updated);
      }
    }
    if (lines.length > 0) {
      setGeneralErrors(generalErrors.filter(m => m !== 'Phải có ít nhất 1 dòng định khoản'));
    }
  };

  const isViewReadOnly = isVoucherFormStatusLocked(status, processingLevel);
  const isFieldLocked = isVoucherFormFieldLocked(status, processingLevel, toolbarMode);
  /** Cash voucher ERP: auto post event — không nút Ghi sổ toolbar (`voucher-form-toolbar.md` §8.16). */
  const showPostButton = false;
  const fp = formPermissions;
  const showEditDelete =
    canShowVoucherEditDelete(status, processingLevel, isNew) && (fp?.canUpdate ?? false);
  const canApprovePermission = fp?.canUnpost ?? fp?.canApprove ?? false;
  const showApproveToolbar = !isNew && canApprovePermission;
  const canApproveToolbar =
    canApprovePermission &&
    canVoucherApprove({
      isNew,
      status,
      processingLevel,
      voucherDate,
      periods: accountingPeriods,
    });
  const canViewLedgerToolbar = canViewVoucherLedgerFromForm({
    isNew,
    id,
    status,
    processingLevel,
    postingStatus,
    canViewLedgerPermission: fp?.canViewLedger ?? false,
  });
  const canCopyToolbar = !isNew && (fp?.canCopy ?? false);
  const canPrintToolbar = !isNew && (fp?.canPrint ?? false);
  const canDeleteToolbar = showEditDelete && (fp?.canDelete ?? false);
  const canSaveToolbar = isNew ? (fp?.canCreate ?? false) : showEditDelete;
  const toolbarDisabledReasons = useMemo(
    () => ({
      ...buildVoucherToolbarDisabledReasons({
        isNew,
        status,
        showPostButton,
        isStatusLocked: isVoucherDocumentTerminalLocked(status),
      }),
      approve: voucherApproveDisabledReason({
        isNew,
        status,
        processingLevel,
        voucherDate,
        periods: accountingPeriods,
      }),
      save: !canSaveToolbar ? 'Không có quyền lưu chứng từ' : undefined,
    }),
    [isNew, status, showPostButton, processingLevel, voucherDate, accountingPeriods, canSaveToolbar],
  );
  const {
    isViewMode,
    isReadOnly,
    viewSectionClass,
    searchViewClass,
    fieldLockProps,
    staticFieldProps,
    searchDisabled,
    textareaClassName,
    textareaReadOnly,
    textareaDisabled,
    selectDisabled,
  } = useFormFieldLock({
    formMode: toolbarMode,
    isStatusLocked: isFieldLocked,
    styles: {
      viewReadOnlySection: styles.viewReadOnlySection,
      searchViewOnly: styles.searchViewOnly,
      embeddedSearch: styles.embeddedSearch,
      textareaReadOnly: styles.textareaReadOnly,
    },
  });

  const ph = (text: string) => fieldPlaceholder(toolbarMode, text, { isStatusLocked: isFieldLocked });

  const searchFieldClass = [searchViewClass, styles.embeddedSearch].filter(Boolean).join(' ');
  const lineAccountSearchClass = [searchViewClass, styles.lineAccountSearch].filter(Boolean).join(' ');

  const searchNavIndex = id ? searchResultIds.indexOf(id) : -1;
  const hasSearchNav = searchNavIndex >= 0 && searchResultIds.length > 0;

  const navigateToSearchId = (targetId: string) => {
    guardedAction(() => navigate(
      `${listPath}/${targetId}`,
      { state: buildVoucherSearchNavigateState(searchResultIds) },
    ));
  };

  const revertToSaved = useCallback(() => {
    if (!savedSnapshot) return;
    const snap = JSON.parse(savedSnapshot) as VoucherFormSnapshot;
    applySnapshot(snap, true);
    clearAllValidation();
  }, [savedSnapshot, applySnapshot, clearAllValidation]);

  const handleBack = () => guardedAction(() => {
    setSearchResultIds([]);
    navigate(listPath);
  });
  const handleNew = () => guardedAction(() => navigate(`${listPath}/them`));
  const handleEdit = () => {
    setFormMode(FormMode.Edit);
    syncEditModeInUrl(FormMode.Edit);
  };
  /** Hủy — bỏ thay đổi, không hiện modal dữ liệu chưa lưu (khác Quay lại). */
  const handleCancel = () => {
    if (formMode === FormMode.Edit) {
      revertToSaved();
      setFormMode(FormMode.View);
      syncEditModeInUrl(FormMode.View);
      return;
    }
    navigate(listPath);
  };
  const handleCopy = () => {
    guardedAction(() => {
      navigate(
        `${listPath}/them`,
        { state: buildVoucherCopyNavigateState(buildSnapshot(), voucherNumber) },
      );
    });
  };
  const handleOpenFromSearch = (voucherId: string, resultIds: string[], items: CashVoucherDto[]) => {
    searchCacheRef.current = voucherSearchCacheToMap(items);
    setSearchResultIds(resultIds);
    guardedAction(() => navigate(
      `${listPath}/${voucherId}`,
      { state: buildVoucherSearchNavigateState(resultIds, items) },
    ));
  };
  const handlePrintConfirm = async (templateId: string) => {
    setPrinting(true);
    try {
      dispatchAppToast(dispatch, {
        message: `In PDF (placeholder) — mẫu: ${templateId}. Triển khai preview/PDF sau.`,
        type: 'info',
      });
      setShowPrintModal(false);
    } finally {
      setPrinting(false);
    }
  };

  const showInitialLoading = initLoading || (loading && !loadedVoucherId);

  const formStateWithLineRows = useMemo(
    () => ({ ...formState, lineRows: formState.lines }),
    [formState],
  );

  const handleApproveConfirm = async (newLevel: string) => {
    setApproving(true);
    const previousLevel = processingLevel;
    try {
      if (!isNew && id) {
        const payload = { ...buildPayload(), processingLevel: newLevel };
        const updated = await cfg.update(id, payload);
        searchCacheRef.current.set(id, updated);
        applyVoucherFromDto(updated, { formMode: FormMode.View });
        dispatchAppToast(dispatch, { message: 'Đã cập nhật mức xử lý', type: 'success' });
        void refreshPostingStatusAfterLevelChange(previousLevel, newLevel, id);
      } else {
        setProcessingLevel(newLevel);
        setSavedSnapshot(serializeVoucherSnapshot({ ...buildSnapshot(), processingLevel: newLevel }));
        dispatchAppToast(dispatch, {
          message: 'Đã cập nhật mức xử lý (lưu cùng chứng từ khi ghi nhận)',
          type: 'success',
        });
      }
      setShowApproveModal(false);
    } catch (e: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(e, 'Cập nhật mức xử lý thất bại. Vui lòng thử lại.'),
        type: 'error',
      });
    } finally {
      setApproving(false);
    }
  };

  return {
    kind,
    cfg,
    labels,
    isNew,
    id,
    navigate,
    dispatch,
    listPath,
    toolbarMode,
    formState: formStateWithLineRows,
    formDispatch,
    voucherDate,
    setVoucherDate,
    voucherNumber,
    setVoucherNumber,
    receiptKind,
    setReceiptKind,
    currencyCode,
    setCurrencyCode,
    exchangeRate,
    setExchangeRate,
    customerId,
    setCustomerId,
    customerCode,
    setCustomerCode,
    customerName,
    setCustomerName,
    customerType,
    setCustomerType,
    representativeName,
    setRepresentativeName,
    customerPhone,
    setCustomerPhone,
    reference,
    setReference,
    referenceCustomerName,
    setReferenceCustomerName,
    accountCode,
    setAccountCode,
    accountName,
    setAccountName,
    counterAccountCode,
    setCounterAccountCode,
    counterAccountName,
    setCounterAccountName,
    description,
    setDescription,
    processingLevel,
    setProcessingLevel,
    isDirty,
    postingReasonCode,
    setPostingReasonCode,
    paymentChannelCode,
    setPaymentChannelCode,
    postingReasonSearchConfig,
    paymentChannelSearchConfig,
    selectedPostingReason,
    selectedPaymentChannel,
    handlePostingReasonSelect,
    handlePostingReasonClear,
    handlePaymentChannelSelect,
    handlePaymentChannelClear,
    showAllowEditPostingCheckbox,
    allowEditPostingAccounts,
    handleAllowEditPostingAccountsChange,
    postingAccountsLocked,
    status,
    loadedVoucherId,
    showInitialLoading,
    initError,
    initLoading,
    lines,
    formMode,
    fieldErrors,
    validationErrors,
    bannerExpanded,
    bannerClosed,
    setBannerExpanded,
    setBannerClosed,
    loading,
    refreshing,
    saving,
    deleting,
    approving,
    printing,
    isViewReadOnly,
    isViewMode,
    isReadOnly,
    viewSectionClass,
    searchViewClass,
    fieldLockProps,
    staticFieldProps,
    searchDisabled,
    textareaClassName,
    textareaReadOnly,
    textareaDisabled,
    selectDisabled,
    ph,
    searchFieldClass,
    lineAccountSearchClass,
    tid,
    validationBannerId,
    totalAmount,
    saveLabel,
    processingOpts,
    receiptKindOpts,
    currencyOptions,
    headerExpanded,
    setHeaderExpanded,
    showHeaderCustomer,
    requireHeaderCustomer,
    showLineCustomer,
    showInvoiceGrid,
    showCounterAccountHeader,
    showDetailObject,
    setShowDetailObject,
    headerCustomerFilterType,
    lineCustomerFilterType,
    showAllocateBtn,
    receiptKindLocked,
    getReceiptKindConflictData,
    showReceiptKindConfirm,
    setShowReceiptKindConfirm,
    receiptKindPendingChange,
    setReceiptKindPendingChange,
    handleReceiptKindConfirmChange,
    handleReceiptKindCancelChange,
    showCustomerConfirm,
    setShowCustomerConfirm,
    customerPendingData,
    setCustomerPendingData,
    handleRequestCustomerChange,
    handleCustomerConfirmChange,
    handleCustomerCancelChange,
    customerSearchConfigOptions,
    hasSearchNav,
    searchNavIndex,
    searchResultIds,
    showSearchSlideout,
    setShowSearchSlideout,
    showApproveModal,
    setShowApproveModal,
    showPrintModal,
    setShowPrintModal,
    showHistoryModal,
    setShowHistoryModal,
    showDeleteModal,
    setShowDeleteModal,
    showConfirmSaveModal,
    setShowConfirmSaveModal,
    handleConfirmSave,
    showLedgerModal,
    setShowLedgerModal,
    showAllocateModal,
    setShowAllocateModal,
    showLinkedInvoicesSlideout,
    setShowLinkedInvoicesSlideout,
    linkedInvoices,
    fmLegacyCode,
    canViewLinkedInvoices,
    showUnsavedModal,
    confirmLeave,
    cancelLeave,
    handleSave,
    handleDelete,
    handleBack,
    handleNew,
    handleEdit,
    handleCancel,
    handleCopy,
    handleApproveConfirm,
    handleOpenFromSearch,
    handleAddLine,
    handleCopyLine,
    handleSelectLine,
    handleRemoveLine,
    selectedLineIndex,
    highlightLineId,
    handleUpdateLine,
    handleAllocateConfirm,
    resolveInvoiceForLine,
    patchHeaderFieldError,
    navigateToSearchId,
    handlePrintConfirm,
    showPostButton,
    showEditDelete,
    showApproveToolbar,
    canApproveToolbar,
    canViewLedger: canViewLedgerToolbar,
    canCopyToolbar,
    canPrintToolbar,
    canDeleteToolbar,
    canSaveToolbar,
    formPermissions: fp,
    postingStatus,
    toolbarDisabledReasons,
    copySourceVoucherCode,
    defaultProcessingLevel: resolvedDefaultProcessingLevel,
    /** Company code the loaded voucher belongs to (null when creating new / same-company). */
    voucherCompanyCode,
    /** VoucherRegistry.Name from CashVoucherDto — SSOT for tab/toolbar title (e.g. "Giấy báo có"). */
    voucherTitle,
    /** VoucherRegistry.Name from init-data — SSOT for form title (e.g. "Giấy báo có"). */
    formTitle,
  };
}

export type CashVoucherFormViewModel = ReturnType<typeof useCashVoucherFormController>;
