import type { CashVoucherKind } from '../../../../../components/kt/CashVoucherList';

export interface PaymentChannelAccountSource {
  debitAccountCode: string;
  creditAccountCode?: string | null;
}

/** Auto-fill TK tiền header from payment channel (P1.2 / GAP-P2-PI-02). */
export function resolvePaymentChannelCashAccount(
  kind: CashVoucherKind,
  channel: PaymentChannelAccountSource,
): string {
  const debit = (channel.debitAccountCode || '').trim();
  const credit = (channel.creditAccountCode || '').trim();
  if (kind === 'receipt') return debit;
  return credit || debit;
}
